import { Injectable } from '@angular/core';
import {
    HttpInterceptor,
    HttpRequest,
    HttpHandler,
    HttpEvent,
    HttpErrorResponse,
    HttpResponse,
    HttpBackend,
    HttpClient
} from '@angular/common/http';
import { Observable, of, throwError } from 'rxjs';
import { catchError, filter, mergeMap, switchMap, take } from 'rxjs/operators';
import { TokenStorageService } from '../services/token-storage.service';
import { Router } from '@angular/router';
import { environment } from 'src/environments/environment';
import { AuthService } from '../auth/services/auth.service';
import { ApiUrls } from '../shared/routes/apiUrl';

interface GetAccessResponse {
    Status: boolean;
    Message: string | null;
    Error: string | null;
    Data: {
        ID: number;
        EmployeeID: number;
        EmpNo: number;
        MarkaziaUserID: string | null;

        FirstName: string | null;
        SecondName: string | null;
        ThirdName: string | null;
        LastName: string | null;

        FirstNameAr: string | null;
        SecondNameAr: string | null;
        LastNameAr: string | null;

        Email: string | null;
        MobileNumber: string | null;
        JobTitle: string | null;
        Name: string | null;

        IsActivite: boolean | null;
        Status: string | null;

        GenderID: number | null;
        GroupID: number | null;
        BusinessAreaID: number | null;
        WorkplaceClassificationID: number | null;
        ContractTypeID: number | null;

        CreatedAt: string | null;
        ModifiedAt: string | null;
        CreatedBy: number | null;
        ModifiedBy: number | null;
        IsDeleted: boolean | null;

        UserWorkingHours: any[];
        UserBusinessAreas: any[];
        Group: any | null;
        UserRoles: any[];
    } | null;
}

@Injectable()
export class JwtInterceptor implements HttpInterceptor {
    private getAccessEndpoint = `${environment.masterBaseUrl.replace(/\/+$/, '')}/${ApiUrls.User.GetAccess.replace(/^\/+/, '')}`;
    private rawHttp: HttpClient;
    private refreshEndpoint = `${environment.masterBaseUrl.replace(/\/+$/, '')}/${ApiUrls.User.RefreshThirdPartyToken.replace(/^\/+/, '')}`;

    constructor(
        private tokenStore: TokenStorageService,
        private authService: AuthService,
        private router: Router,
        handler: HttpBackend
    ) {
        this.rawHttp = new HttpClient(handler);
    }

    private isTokenEndpoint(url: string): boolean {
        return url.startsWith(this.getAccessEndpoint) || url.startsWith(this.refreshEndpoint);
    }

    intercept(req: HttpRequest<any>, next: HttpHandler): Observable<HttpEvent<any>> {
        const localToken = this.tokenStore.token;
        const ssoAccess = this.tokenStore.ssoAccessToken;
        const inSsoMode = this.tokenStore.isSingleSignOnMode;

        const tokenToUse = this.isTokenEndpoint(req.url)
            ? (ssoAccess || localToken || null)
            : (localToken || ssoAccess || null);

        const authedReq = tokenToUse ? this.addAuth(req, tokenToUse) : req;

        return next.handle(authedReq).pipe(
            mergeMap(event => {
                if (event instanceof HttpResponse) {
                    const body = event.body;

                    if (event.url?.startsWith(this.getAccessEndpoint) && body?.Status === true) {
                        this.saveUserFromGetAccess(body as GetAccessResponse);
                    }

                    if (
                        body?.Status === false &&
                        (body?.Error === 'Token has expired' || body?.Message === 'Token has expired')
                    ) {
                        const ssoRefresh = this.tokenStore.ssoRefreshToken;
                        if (inSsoMode && ssoRefresh) {
                            return this.refreshAndRetry(req, next, ssoRefresh);
                        }
                    }
                }
                return of(event);
            }),

            catchError((err: any) => {
                return this.handleError(err, authedReq, next);
            })
        );
    }

    private saveUserFromGetAccess(res: GetAccessResponse) {
        const d = res?.Data;
        if (!d) return;

        const id =
            (d.EmployeeID && d.EmployeeID !== 0) ? d.EmployeeID :
                (d.ID && d.ID !== 0) ? d.ID :
                    d.MarkaziaUserID ?? null;

        const fullName =
            [d.FirstName, d.SecondName, d.ThirdName, d.LastName]
                .filter(Boolean)
                .join(' ')
            || d.Email
            || '';

        this.tokenStore.saveUser({
            nameid: id,
            UserID: id,
            EmployeeID: d.EmployeeID ?? d.ID ?? null,
            EmpNo: d.EmpNo ?? null,
            Email: d.Email ?? '',
            fullName,
            userPortals: []
        });

        this.tokenStore.saveEmployeeInfo(res);
    }

    private handleError(err: any, req: HttpRequest<any>, next: HttpHandler): Observable<HttpEvent<any>> {
        if (err instanceof HttpErrorResponse && err.status === 401) {
            const message = err?.error?.Message || err?.error?.Error || err?.message || '';
            const expired = /expired|invalid/i.test(message);

            if (expired) {
                const refreshToken = this.tokenStore.ssoRefreshToken;
                if (refreshToken) {
                    return this.refreshAndRetry(req, next, refreshToken);
                }
            }
        }
        return throwError(() => err);
    }

    private refreshAndRetry(req: HttpRequest<any>, next: HttpHandler, refreshToken: string): Observable<HttpEvent<any>> {
        const { isRefreshing, tokenSubject } = this.authService.getRefreshState();

        if (!isRefreshing) {
            return this.authService.refreshToken(refreshToken).pipe(
                switchMap(({ accessToken }) => {
                    const retried = this.addAuth(req, accessToken);
                    return next.handle(retried);
                }),
                catchError(e => throwError(() => e))
            );
        }

        return tokenSubject.pipe(
            filter(t => !!t),
            take(1),
            switchMap(t => next.handle(this.addAuth(req, t!)))
        );
    }

    private addAuth(req: HttpRequest<any>, token: string): HttpRequest<any> {
        if (this.tokenStore.isSingleSignOnMode) {
            return req.clone({
                setHeaders: {
                    HubAuthorization: `Bearer ${token}`
                }
            });
        } else {
            return req.clone({
                setHeaders: {
                    Authorization: `Bearer ${token}`
                }
            });
        }
    }
}
